                                    <th style={styles.th}>Size</th><th style={styles.th}>MRP</th><th style={styles.th}>Qty</th>
                                </tr></thead>
                                <tbody>
                                    {(order.lineItems || []).map((item, index) => (
                                        <tr key={item.barcode ?? index} style={index % 2 !== 0 ? {backgroundColor: 'var(--stripe-bg)'} : {}}>
