        finally { setIsLoading(false); }
    };

    const handleLogout = () => {
        localStorage.removeItem('ka-oms-session');
        setIsLoggedIn(false);
        setSession(null);
        setUserId('');
        setPassword('');
        clearUserIdFromDB();
    };

    const updateUserProfile = (newName, newAvatarId) => {
