const UserAvatar = ({ name, avatarId, size = 'small', style = {} }) => {
    const isLarge = size === 'large';
    const isMedium = size === 'medium';
    const dim = isLarge ? 80 : (isMedium ? 30 : 40); 
    const fontSize = isLarge ? '2.5rem' : (isMedium ? '1rem' : '1.2rem');

    const safeId = typeof avatarId === 'number' && avatarId >= 0 && avatarId <= 7 ? avatarId : 0;

    const containerStyle = {
        width: `${dim}px`, 
        height: `${dim}px`, 
        borderRadius: '50%', 
        overflow: 'hidden',
        backgroundColor: safeId === 0 ? 'var(--brand-color)' : 'transparent',
        color: '#fff', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'center',
        fontSize: fontSize, 
        fontWeight: 600,
        boxShadow: '0 2px 5px rgba(0,0,0,0.1)',
        flexShrink: 0,
        ...style
    };

    const renderContent = () => {
        switch(safeId) {
            case 1: return <AvatarOne />;
            case 2: return <AvatarTwo />;
            case 3: return <AvatarThree />;
            case 4: return <AvatarFour />;
            case 5: return <AvatarFive />;
            case 6: return <AvatarSix />;
            case 7: return <AvatarSeven />;
            case 0:
            default: return name ? name.charAt(0).toUpperCase() : 'U';
        }
    };

    return (
        <div style={containerStyle}>
            {renderContent()}
        </div>
    );
};

// --- DATABASE LOGIC for user ID ---
const DB_NAME = 'user-session-db';
const DB_VERSION = 1;
const STORE_NAME = 'user';
const USER_ID_KEY = 'currentUserId';

const openUserDb = () => {
    return new Promise<IDBDatabase>((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = () => {
            const db = request.result;
            if (!db.objectStoreNames.contains(STORE_NAME)) {
                db.createObjectStore(STORE_NAME, { keyPath: 'id' });
            }
        };
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
};

const saveUserIdToDB = async (userId: string) => {
    try {
        const db = await openUserDb();
        const transaction = db.transaction(STORE_NAME, 'readwrite');
        const store = transaction.objectStore(STORE_NAME);
        store.put({ id: USER_ID_KEY, userId });
        await new Promise<void>((resolve, reject) => {
            transaction.oncomplete = () => resolve();
            transaction.onerror = (event: any) => reject(event.target.error);
        });
        console.log('User ID saved to IndexedDB');
    } catch (error) {
        console.error('Failed to save user ID to IndexedDB:', error);
    }
};

const clearUserIdFromDB = async () => {
    try {
        const db = await openUserDb();
        const transaction = db.transaction(STORE_NAME, 'readwrite');
        const store = transaction.objectStore(STORE_NAME);
        store.delete(USER_ID_KEY);
        await new Promise<void>((resolve, reject) => {
            transaction.oncomplete = () => resolve();
            transaction.onerror = (event: any) => reject(event.target.error);
        });
        console.log('User ID cleared from IndexedDB');
    } catch (error) {
        console.error('Failed to clear user ID from IndexedDB:', error);
    }
};


