    if (isLoggedIn && session) {
        return <HomePage session={session} onLogout={handleLogout} appLogoSrc={appLogoSrc} updateUserProfile={updateUserProfile} />;
    }

    const mobileLoginContainerStyle = {
        ...styles.mobileInputContainer,
