                                display: 'flex',
                                width: '200%',
                                transform: isForgotPassword ? 'translateX(-50%)' : 'translateX(0)',
                                transition: 'transform 0.5s cubic-bezier(0.77, 0, 0.175, 1)'
                            }}>
                                <div style={{width: '50%', flexShrink: 0}}>
                                    <form onSubmit={handleLogin} style={styles.form}>
